#if UNITY_EDITOR
using System;
using System.Collections.Generic;
using System.Globalization;
using System.Text;
using UnityEditor;
using UnityEngine;

/// <summary>
/// Validador global de dados do jogo (pedidos "Dados e IDs" e "Ferramentas
/// internas, validação e testes"): com 34 animais, 40 áreas e centenas de
/// objectos persistentes, IDs escritos à mão são uma fonte de bugs — esta
/// janela varre todos os ScriptableObjects do projecto e reporta:
///
/// - IDs vazios ou duplicados (AreaData, AnimalFormData, ItemData,
///   UpgradeData, MissionData, EmblemData, WorldData, ChallengeDefinition);
/// - assets que existem no projecto mas não estão registados no
///   GameDatabase (Assets/Resources/GameDatabase.asset);
/// - referências em falta mais comuns (AreaData sem "world", AnimalFormData
///   sem "originWorld", EmblemData sem "obtainedVariable");
/// - nomes de variáveis (GameVariables) duplicados entre ChallengeDefinitions
///   — "Desafio_&lt;id&gt;_Ativo"/"_Concluido" (derivados ou com override em
///   "activeVariableName"/"completedVariableName") têm de ser únicos, ou dois
///   desafios partilhariam o mesmo estado "activo"/"concluído".
///
/// ChallengeDefinition não tem lista própria no GameDatabase (é referenciada
/// directamente por ChallengeTrigger/Action_StartChallenge, sem registo
/// central) — por isso não entra em "CheckGameDatabaseRegistration".
///
/// Botão "Gerar IDs em falta" cria um ID legível (slug do "displayName") para
/// cada asset com ID vazio — não resolve duplicados automaticamente (decisão
/// de design, requer revisão humana).
///
/// Acesso: menu "Animals/Validar Dados do Jogo".
/// </summary>
public class GameDataValidatorWindow : EditorWindow
{
    [MenuItem("Animals/Validar Dados do Jogo")]
    public static void ShowWindow()
    {
        GetWindow<GameDataValidatorWindow>("Validador de Dados");
    }

    private readonly List<string> _errors = new List<string>();
    private readonly List<string> _warnings = new List<string>();
    private readonly List<(ScriptableObject asset, string fieldName)> _missingIds = new List<(ScriptableObject, string)>();

    private Vector2 _scroll;
    private bool _ranOnce;

    private void OnGUI()
    {
        EditorGUILayout.HelpBox(
            "Varre todos os ScriptableObjects do projecto (AreaData, AnimalFormData, " +
            "ItemData, UpgradeData, MissionData, EmblemData, WorldData, ChallengeDefinition) " +
            "à procura de IDs vazios/duplicados, registo em falta no GameDatabase, variáveis " +
            "de Desafio duplicadas e referências em falta.",
            MessageType.None);

        EditorGUILayout.Space();

        using (new EditorGUILayout.HorizontalScope())
        {
            if (GUILayout.Button("Validar Agora", GUILayout.Height(28)))
                Validate();

            GUI.enabled = _missingIds.Count > 0;
            if (GUILayout.Button($"Gerar IDs em Falta ({_missingIds.Count})", GUILayout.Height(28)))
                GenerateMissingIds();
            GUI.enabled = true;
        }

        EditorGUILayout.Space();

        if (!_ranOnce)
        {
            EditorGUILayout.HelpBox("Clica em \"Validar Agora\" para correr a verificação.", MessageType.Info);
            return;
        }

        EditorGUILayout.LabelField($"{_errors.Count} erro(s), {_warnings.Count} aviso(s).", EditorStyles.boldLabel);

        _scroll = EditorGUILayout.BeginScrollView(_scroll);

        if (_errors.Count == 0 && _warnings.Count == 0)
            EditorGUILayout.HelpBox("Sem problemas encontrados.", MessageType.Info);

        foreach (var e in _errors)
            EditorGUILayout.HelpBox(e, MessageType.Error);

        foreach (var w in _warnings)
            EditorGUILayout.HelpBox(w, MessageType.Warning);

        EditorGUILayout.EndScrollView();
    }

    private void Validate()
    {
        _errors.Clear();
        _warnings.Clear();
        _missingIds.Clear();

        CheckIds<AreaData>(a => a.areaId, "areaId", a => a.displayName);
        CheckIds<AnimalFormData>(a => a.formId, "formId", a => a.displayName);
        CheckIds<ItemData>(a => a.itemId, "itemId", a => a.displayName);
        CheckIds<UpgradeData>(a => a.upgradeId, "upgradeId", a => a.displayName);
        CheckIds<MissionData>(a => a.missionId, "missionId", a => a.displayName);
        CheckIds<EmblemData>(a => a.emblemId, "emblemId", a => a.displayName);
        CheckIds<WorldData>(a => a.worldId, "worldId", a => a.displayName);
        CheckIds<ChallengeDefinition>(a => a.challengeId, "challengeId", a => a.displayName);

        CheckGameDatabaseRegistration();
        CheckCommonReferences();
        CheckChallengeVariables();
        CheckShopItemMixup();
        CheckDeprecatedComponents();

        _ranOnce = true;
        Debug.Log($"[GameDataValidator] Validação concluída: {_errors.Count} erro(s), {_warnings.Count} aviso(s).");
    }

    // ---------------- IDs vazios / duplicados ----------------

    private void CheckIds<T>(Func<T, string> getId, string fieldName, Func<T, string> getName) where T : ScriptableObject
    {
        string typeName = typeof(T).Name;
        var seen = new Dictionary<string, string>();

        foreach (var asset in FindAssets<T>())
        {
            string id = getId(asset);
            string path = AssetDatabase.GetAssetPath(asset);
            string label = !string.IsNullOrEmpty(getName(asset)) ? getName(asset) : asset.name;

            if (string.IsNullOrEmpty(id))
            {
                _errors.Add($"{typeName}: \"{label}\" ({path}) tem '{fieldName}' vazio.");
                _missingIds.Add((asset, fieldName));
                continue;
            }

            if (seen.TryGetValue(id, out var otherPath))
                _errors.Add($"{typeName}: ID duplicado '{id}' em \"{path}\" e \"{otherPath}\".");
            else
                seen[id] = path;
        }
    }

    // ---------------- Registo no GameDatabase ----------------

    private void CheckGameDatabaseRegistration()
    {
        var db = GameDatabase.Instance;
        if (db == null)
        {
            _warnings.Add("GameDatabase não encontrado em Assets/Resources/GameDatabase.asset — verificação de registo saltada.");
            return;
        }

        CheckRegistered(FindAssets<WorldData>(), db.worlds, "WorldData");
        CheckRegistered(FindAssets<AreaData>(), db.areas, "AreaData");
        CheckRegistered(FindAssets<AnimalFormData>(), db.animalForms, "AnimalFormData");
        CheckRegistered(FindAssets<ItemData>(), db.items, "ItemData");
        CheckRegistered(FindAssets<UpgradeData>(), db.upgrades, "UpgradeData");
        CheckRegistered(FindAssets<MissionData>(), db.missions, "MissionData");
        CheckRegistered(FindAssets<EmblemData>(), db.emblems, "EmblemData");
    }

    private void CheckRegistered<T>(List<T> all, List<T> registered, string typeName) where T : ScriptableObject
    {
        foreach (var asset in all)
        {
            bool found = registered != null && registered.Contains(asset);
            if (!found)
                _warnings.Add($"{typeName} \"{asset.name}\" ({AssetDatabase.GetAssetPath(asset)}) não está registado no GameDatabase.");
        }
    }

    // ---------------- Referências comuns em falta ----------------

    private void CheckCommonReferences()
    {
        foreach (var area in FindAssets<AreaData>())
        {
            if (area.world == null)
                _warnings.Add($"AreaData \"{area.displayName}\" ({AssetDatabase.GetAssetPath(area)}) não tem 'world' atribuído.");
        }

        foreach (var emblem in FindAssets<EmblemData>())
        {
            if (string.IsNullOrEmpty(emblem.obtainedVariable))
                _warnings.Add($"EmblemData \"{emblem.displayName}\" ({AssetDatabase.GetAssetPath(emblem)}) não tem 'obtainedVariable' definido — nunca será contado em GetTotalCompletionPercent.");
        }
    }

    // ---------------- Variáveis de Desafio duplicadas ----------------

    /// <summary>
    /// "ActiveVariable"/"CompletedVariable" (Desafio_&lt;id&gt;_Ativo/_Concluido,
    /// ou override em "activeVariableName"/"completedVariableName") têm de ser
    /// únicos entre TODOS os ChallengeDefinition — caso contrário dois desafios
    /// partilhariam o mesmo estado em GameVariables (ex: um termina e desliga a
    /// variável "activo" do outro). IDs vazios já são reportados por
    /// CheckIds&lt;ChallengeDefinition&gt; e ignorados aqui (a variável derivada
    /// seria "Desafio__Ativo" para todos, mas o erro de ID vazio já cobre isso).
    /// </summary>
    private void CheckChallengeVariables()
    {
        var seen = new Dictionary<string, string>();

        foreach (var challenge in FindAssets<ChallengeDefinition>())
        {
            if (string.IsNullOrEmpty(challenge.challengeId)) continue;

            string path = AssetDatabase.GetAssetPath(challenge);
            CheckVariable(challenge.ActiveVariable, "ActiveVariable", path, seen);
            CheckVariable(challenge.CompletedVariable, "CompletedVariable", path, seen);
        }
    }

    private void CheckVariable(string name, string fieldLabel, string path, Dictionary<string, string> seen)
    {
        if (string.IsNullOrEmpty(name)) return;

        if (seen.TryGetValue(name, out var otherPath))
            _errors.Add($"ChallengeDefinition: variável '{name}' ({fieldLabel}) duplicada entre \"{path}\" e \"{otherPath}\".");
        else
            seen[name] = path;
    }

    // ---------------- Geração de IDs em falta ----------------

    private void GenerateMissingIds()
    {
        var usedIds = new HashSet<string>();

        // Pré-carrega IDs já existentes de cada tipo para evitar colisões com o novo slug.
        CollectExistingIds<AreaData>(a => a.areaId, usedIds);
        CollectExistingIds<AnimalFormData>(a => a.formId, usedIds);
        CollectExistingIds<ItemData>(a => a.itemId, usedIds);
        CollectExistingIds<UpgradeData>(a => a.upgradeId, usedIds);
        CollectExistingIds<MissionData>(a => a.missionId, usedIds);
        CollectExistingIds<EmblemData>(a => a.emblemId, usedIds);
        CollectExistingIds<WorldData>(a => a.worldId, usedIds);
        CollectExistingIds<ChallengeDefinition>(a => a.challengeId, usedIds);

        foreach (var (asset, fieldName) in _missingIds)
        {
            var field = asset.GetType().GetField(fieldName);
            if (field == null) continue;

            string displayName = GetDisplayName(asset);
            string slug = Slugify(string.IsNullOrEmpty(displayName) ? asset.name : displayName);

            string unique = slug;
            int suffix = 2;
            while (usedIds.Contains(unique))
                unique = $"{slug}_{suffix++}";

            usedIds.Add(unique);

            Undo.RecordObject(asset, "Gerar ID");
            field.SetValue(asset, unique);
            EditorUtility.SetDirty(asset);
        }

        AssetDatabase.SaveAssets();
        Debug.Log($"[GameDataValidator] {_missingIds.Count} ID(s) gerado(s) automaticamente a partir do nome de exibição. Revê os assets alterados antes de fazer commit.");

        Validate();
    }

    private void CollectExistingIds<T>(Func<T, string> getId, HashSet<string> into) where T : ScriptableObject
    {
        foreach (var asset in FindAssets<T>())
        {
            string id = getId(asset);
            if (!string.IsNullOrEmpty(id)) into.Add(id);
        }
    }

    private static string GetDisplayName(ScriptableObject asset)
    {
        var field = asset.GetType().GetField("displayName");
        return field != null ? field.GetValue(asset) as string : null;
    }

    /// <summary>Converte texto (incluindo acentos em português) num slug em snake_case, ex: "Bosque de Bruma" → "bosque_de_bruma".</summary>
    private static string Slugify(string text)
    {
        if (string.IsNullOrEmpty(text)) return "sem_nome";

        string normalized = text.Normalize(NormalizationForm.FormD);
        var sb = new StringBuilder();

        foreach (char c in normalized)
        {
            var category = CharUnicodeInfo.GetUnicodeCategory(c);
            if (category == UnicodeCategory.NonSpacingMark) continue;

            if (char.IsLetterOrDigit(c))
                sb.Append(char.ToLowerInvariant(c));
            else if (sb.Length > 0 && sb[sb.Length - 1] != '_')
                sb.Append('_');
        }

        string result = sb.ToString().Trim('_');
        return string.IsNullOrEmpty(result) ? "sem_nome" : result;
    }

    // ---------------- Task #13: BrotoDeVida vs SeivaVital em lojas ----------------

    private void CheckShopItemMixup()
    {
        foreach (var shop in FindAssets<ShopData>())
        {
            if (shop.entries == null) continue;
            string shopPath = AssetDatabase.GetAssetPath(shop);

            foreach (var entry in shop.entries)
            {
                if (entry?.item == null) continue;

                string id   = entry.item.itemId ?? "";
                string name = entry.item.displayName ?? entry.item.name ?? "";

                bool looksLikeBroto =
                    id.IndexOf("broto", System.StringComparison.OrdinalIgnoreCase) >= 0 ||
                    name.IndexOf("Broto de Vida", System.StringComparison.OrdinalIgnoreCase) >= 0;

                if (looksLikeBroto)
                    _warnings.Add(
                        $"[Task #13] ShopData \"{shop.shopName}\" ({shopPath}) vende \"{name}\" " +
                        $"(id: '{id}'). O Broto de Vida é um drop de chão e NÃO deve ser " +
                        "vendido em lojas (GDD linha 3601). Substitui pelo item Seiva Vital " +
                        "(effectType = CuraInstantanea).");
            }
        }
    }

    // ---------------- Componentes obsoletos em prefabs ----------------

    /// <summary>
    /// Task #5: SussurroDaTerraPickup contradiz o GDD — emite aviso se encontrado
    /// em qualquer prefab do projecto.
    /// </summary>
    private void CheckDeprecatedComponents()
    {
        foreach (var guid in AssetDatabase.FindAssets("t:Prefab"))
        {
            string path = AssetDatabase.GUIDToAssetPath(guid);
            var go = AssetDatabase.LoadAssetAtPath<GameObject>(path);
            if (go == null) continue;

            if (go.GetComponentInChildren<SussurroDaTerraPickup>(true) != null)
                _warnings.Add(
                    $"[Obsoleto] Prefab \"{go.name}\" ({path}) contém SussurroDaTerraPickup. " +
                    "Segundo o GDD, Sussurros são comprados ao NPC Contador de Histórias — " +
                    "não são pickups físicos. Remove o componente e usa uma Action de diálogo.");
        }
    }

    // ---------------- Util ----------------

    private static List<T> FindAssets<T>() where T : ScriptableObject
    {
        var result = new List<T>();
        foreach (var guid in AssetDatabase.FindAssets($"t:{typeof(T).Name}"))
        {
            var asset = AssetDatabase.LoadAssetAtPath<T>(AssetDatabase.GUIDToAssetPath(guid));
            if (asset != null) result.Add(asset);
        }
        return result;
    }
}
#endif
